      umap = sprintf("umap_%s_dims%d", branch_tag, d),
      color_by = sprintf("cluster_%s_dims%d_res%s", branch_tag, d, res_tag(r))
    )
  }
}

min_clustree_resolutions <- 2L
clustree_plotted <- length(unique(resolutions)) >= min_clustree_resolutions
if (clustree_plotted) {
  for (d in dims_grid) {
    splot_clustree(
      sobj,
      prefix = sprintf("cluster_%s_dims%d_res", branch_tag, d),
      out_tag = sprintf("%s_dims%d", branch_tag, d)
    )
  }
} else {
  message(
    "Skipping clustree output because fewer than two resolutions were requested."
  )
}

sobj@misc$clustering <- list(
  algorithm = "leiden",
  filtered_cell_cycle = isTRUE(sobj@misc$preprocessing$filtered_cell_cycle),
  branch_tag = branch_tag,
  resolutions = resolutions,
  dims_grid = dims_grid,
  elbow_n = elbow_n,
  candidate_names = candidate_names,
  clustree_plotted = clustree_plotted
)

# ---- output ----

out_path <- file.path(
  CURRENT_OBJECT_DIR,
  sprintf("cluster_%s_elbow%d.rds", branch_tag, elbow_n)
)

dir.create(CURRENT_OBJECT_DIR, recursive = TRUE, showWarnings = FALSE)
saveRDS(sobj, out_path)
emit_tripwire_checkpoint(
  "cluster_artifacts_written",
  output = out_path,
  branch_tag = branch_tag,
  n_candidates = length(candidate_names)
)
message("Saved ", out_path)

#!/usr/bin/env Rscript

# Summarize and plot the mg-selected PFlog clustering grid.
#
# Usage:
#   Rscript scripts/08-summarize-mg-clusters.R [--elbow-n <positive integer>]
#
# Inputs:
#   CURRENT_OBJECT_DIR/cluster_pflog_mg_selected_no_filter_cc_elbow<N>.rds
#   CURRENT_OBJECT_DIR/cluster_pflog_mg_selected_filter_cc_elbow<N>.rds
#
# Outputs:
#   TABLE_DIR/mg_selected/mg_selected_cluster_grid_summary.tsv
#   FIGURE_DIR/mg_selected/mg_selected_umap_resolution_sweep_<branch>_dims<dims>.(png|pdf)
#   notebook/figures/<sweep png filename> symlinks.

suppressPackageStartupMessages({
  library(here)
})
here::i_am("scripts/08-summarize-mg-clusters.R")
suppressPackageStartupMessages({
  devtools::load_all(here::here(), export_all = FALSE, quiet = TRUE)
})

# ---- parameters ----

get_arg <- function(args, flag, default) {
  match_index <- match(flag, args)
  if (is.na(match_index)) {
    return(default)
  }
  if (
    match_index == length(args) || startsWith(args[[match_index + 1]], "--")
  ) {
    stop("Missing value for ", flag, call. = FALSE)
  }
  args[[match_index + 1]]
}

cli_args <- commandArgs(trailingOnly = TRUE)
allowed_flags <- c("--elbow-n")
unknown_flags <- cli_args[
  startsWith(cli_args, "--") & !cli_args %in% allowed_flags
]
if (length(unknown_flags) > 0) {
  stop(
    "Unknown argument(s): ",
    paste(unknown_flags, collapse = ", "),
    call. = FALSE
  )
}

elbow_n <- as.integer(get_arg(cli_args, "--elbow-n", "20"))
if (length(elbow_n) != 1L || is.na(elbow_n) || elbow_n <= 0) {
  stop("--elbow-n must be a positive integer.", call. = FALSE)
}

MG_SELECTED_BRANCHES <- data.frame(
  branch_tag = c(
    "pflog_mg_selected_no_filter_cc",
    "pflog_mg_selected_filter_cc"
  ),
  filtered_cell_cycle = c(FALSE, TRUE),
  stringsAsFactors = FALSE
)
MG_SELECTED_SMALL_CLUSTER_THRESHOLD <- 50L
MG_SELECTED_SWEEP_PANEL_WIDTH <- 3.6
MG_SELECTED_SWEEP_HEIGHT <- 4.2

# ---- helpers ----

mg_selected_object_path <- function(branch_tag, elbow_n) {
  file.path(
    CURRENT_OBJECT_DIR,
    sprintf("cluster_%s_elbow%d.rds", branch_tag, elbow_n)
  )
}

mg_selected_res_tag <- function(resolution) {
  format(resolution, trim = TRUE, scientific = FALSE)
}

parse_mg_selected_cluster_column <- function(column, branch_tag) {
  pattern <- sprintf("^cluster_%s_dims([0-9]+)_res(.+)$", branch_tag)
  hit <- regexec(pattern, column, perl = TRUE)
  parts <- regmatches(column, hit)[[1]]
  if (length(parts) != 3L) {
    stop("Cannot parse mg-selected cluster column: ", column, call. = FALSE)
  }
  resolution <- suppressWarnings(as.numeric(parts[[3L]]))
  if (is.na(resolution) || !is.finite(resolution) || resolution <= 0) {
    stop("Invalid resolution in cluster column: ", column, call. = FALSE)
  }
  data.frame(
    cluster_column = column,
    dims = as.integer(parts[[2L]]),
    resolution = resolution,
    stringsAsFactors = FALSE
  )
}

mg_selected_candidate_columns <- function(sobj, branch_tag) {
  candidate_names <- sobj@misc$clustering$candidate_names
  if (!is.character(candidate_names) || length(candidate_names) == 0L) {
    stop(
      "Missing sobj@misc$clustering$candidate_names for branch: ",
      branch_tag,
      call. = FALSE
    )
  }
  if (anyNA(candidate_names) || any(!nzchar(candidate_names))) {
    stop(
      "Invalid empty candidate cluster column name for branch: ",
      branch_tag,
      call. = FALSE
    )
  }
  missing_columns <- setdiff(candidate_names, colnames(sobj@meta.data))
  if (length(missing_columns) > 0L) {
    stop(
      "Missing candidate cluster column(s): ",
      paste(missing_columns, collapse = ", "),
      call. = FALSE
    )
  }
  parsed <- lapply(
    candidate_names,
    parse_mg_selected_cluster_column,
    branch_tag = branch_tag
  )
  candidates <- do.call(rbind, parsed)
  candidates <- candidates[order(candidates$dims, candidates$resolution), ]
  rownames(candidates) <- NULL
  candidates
}

mg_selected_size_summary <- function(labels) {
  if (anyNA(labels)) {
    stop("Cluster labels contain NA values.", call. = FALSE)
  }
  cluster_sizes <- table(as.character(labels))
  small_clusters <- cluster_sizes[
    cluster_sizes < MG_SELECTED_SMALL_CLUSTER_THRESHOLD
  ]
  data.frame(
    n_cells = length(labels),
    n_clusters = length(cluster_sizes),
    min_cluster_size = as.integer(min(cluster_sizes)),
    q25_cluster_size = as.numeric(stats::quantile(
      cluster_sizes,
      0.25,
      names = FALSE
    )),
    median_cluster_size = as.numeric(stats::median(cluster_sizes)),
    max_cluster_size = as.integer(max(cluster_sizes)),
    n_clusters_lt50 = length(small_clusters),
    fraction_clusters_lt50 = length(small_clusters) / length(cluster_sizes),
    stringsAsFactors = FALSE
  )
}

load_mg_selected_objects <- function(branches, elbow_n) {
  objects <- vector("list", nrow(branches))
  names(objects) <- branches$branch_tag
  for (i in seq_len(nrow(branches))) {
    branch_tag <- branches$branch_tag[[i]]
    object_path <- mg_selected_object_path(branch_tag, elbow_n)
    if (!file.exists(object_path)) {
      stop("Missing clustered mg-selected object: ", object_path, call. = FALSE)
    }
    sobj <- readRDS(object_path)
    object_branch_tag <- sobj@misc$clustering$branch_tag
    if (
      is.character(object_branch_tag) &&
        length(object_branch_tag) == 1L &&
        nzchar(object_branch_tag) &&
        !identical(object_branch_tag, branch_tag)
    ) {
      stop(
        "Object branch tag mismatch for ",
        object_path,
        ": expected ",
        branch_tag,
        ", found ",
        object_branch_tag,
        call. = FALSE
      )
    }
    objects[[branch_tag]] <- sobj
  }
  objects
}

collect_mg_selected_summary <- function(objects, branches) {
  rows <- list()
  idx <- 1L
  for (i in seq_len(nrow(branches))) {
    branch_info <- branches[i, ]
    sobj <- objects[[branch_info$branch_tag]]
    candidates <- mg_selected_candidate_columns(sobj, branch_info$branch_tag)
    for (j in seq_len(nrow(candidates))) {
      candidate <- candidates[j, ]
      labels <- sobj@meta.data[[candidate$cluster_column]]
      rows[[idx]] <- cbind(
        data.frame(
          branch_tag = branch_info$branch_tag,
          filtered_cell_cycle = branch_info$filtered_cell_cycle,
          dims = candidate$dims,
          resolution = candidate$resolution,
          cluster_column = candidate$cluster_column,
          stringsAsFactors = FALSE
        ),
        mg_selected_size_summary(labels)
      )
      idx <- idx + 1L
    }
  }
  summary <- do.call(rbind, rows)
  summary <- summary[
    order(
      summary$branch_tag,
      summary$dims,
      summary$resolution
    ),
  ]
  rownames(summary) <- NULL
  summary
}


save_mg_selected_resolution_sweeps <- function(objects, branches) {
  out_dir <- file.path(FIGURE_DIR, "mg_selected")
  dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
  linked_paths <- character()

  for (i in seq_len(nrow(branches))) {
    branch_info <- branches[i, ]
    branch_tag <- branch_info$branch_tag
    sobj <- objects[[branch_tag]]
    candidates <- mg_selected_candidate_columns(sobj, branch_tag)
    for (dims in sort(unique(candidates$dims))) {
      reduction <- sprintf("umap_%s_dims%d", branch_tag, dims)
      if (!reduction %in% names(sobj@reductions)) {
        stop("Missing UMAP reduction: ", reduction, call. = FALSE)
      }
      dim_candidates <- candidates[candidates$dims == dims, ]
      dim_candidates <- dim_candidates[order(dim_candidates$resolution), ]
      plots <- lapply(seq_len(nrow(dim_candidates)), function(row_idx) {
        candidate <- dim_candidates[row_idx, ]
        column <- candidate$cluster_column
        if (!column %in% colnames(sobj@meta.data)) {
          stop("Missing cluster metadata column: ", column, call. = FALSE)
        }
        Seurat::DimPlot(
          sobj,
          reduction = reduction,
          group.by = column,
          label = TRUE,
          pt.size = 0.25
        ) +
          ggplot2::ggtitle(sprintf(
            "res %s",
            mg_selected_res_tag(candidate$resolution)
          )) +
          ggplot2::labs(x = "UMAP 1", y = "UMAP 2") +
          ggplot2::theme(
            legend.position = "none",
            plot.title = ggplot2::element_text(size = 11)
          )
      })
      plot <- patchwork::wrap_plots(plots, ncol = nrow(dim_candidates)) +
        patchwork::plot_annotation(
          title = sprintf("%s; %d PCs", branch_tag, dims)
        )
      out_tag <- sprintf(
        "mg_selected_umap_resolution_sweep_%s_dims%d",
        branch_tag,
        dims
      )
      png_path <- file.path(out_dir, sprintf("%s.png", out_tag))
      pdf_path <- file.path(out_dir, sprintf("%s.pdf", out_tag))
      ggplot2::ggsave(
        png_path,
        plot,
        width = MG_SELECTED_SWEEP_PANEL_WIDTH * nrow(dim_candidates),
        height = MG_SELECTED_SWEEP_HEIGHT
      )
      ggplot2::ggsave(
        pdf_path,
        plot,
        width = MG_SELECTED_SWEEP_PANEL_WIDTH * nrow(dim_candidates),
        height = MG_SELECTED_SWEEP_HEIGHT
      )
      linked_paths <- c(linked_paths, link_notebook_png(png_path))
    }
  }

  linked_paths
}

# ---- work ----

objects <- load_mg_selected_objects(MG_SELECTED_BRANCHES, elbow_n = elbow_n)
summary <- collect_mg_selected_summary(objects, MG_SELECTED_BRANCHES)

# ---- output ----

summary_path <- file.path(
  TABLE_DIR,
  "mg_selected",
  "mg_selected_cluster_grid_summary.tsv"
)
dir.create(dirname(summary_path), recursive = TRUE, showWarnings = FALSE)
utils::write.table(
  summary,
  summary_path,
  sep = "\t",
  quote = FALSE,
  row.names = FALSE,
  na = ""
)
linked_paths <- save_mg_selected_resolution_sweeps(
  objects,
  MG_SELECTED_BRANCHES
)

message(
  "Wrote mg-selected cluster grid summary with ",
  nrow(summary),
  " rows to ",
  summary_path
)
message(
  "Wrote mg-selected UMAP resolution sweeps to ",
  file.path(FIGURE_DIR, "mg_selected")
)
message("Linked notebook figure(s): ", paste(linked_paths, collapse = ", "))

#!/usr/bin/env Rscript

# Print the deterministic analysis plan or perform its execution preflight.
#
# Usage:
#   Rscript scripts/run-pipeline.R --dry-run \
#     [--input-source counts-qc|legacy | --input <seurat.rds>] [--overwrite]
#
# Arguments:
#   --dry-run       Print the pipeline contract without checking or writing inputs.
#   --input-source  Use the named counts-qc or legacy source object.
#   --input         Use an explicit Seurat RDS input path.
#   --overwrite     Permit replacement of protected marker and DE outputs.

suppressPackageStartupMessages({
  library(here)
})
suppressMessages(here::i_am("scripts/run-pipeline.R"))
suppressPackageStartupMessages({
  devtools::load_all(here::here(), export_all = FALSE, quiet = TRUE)
})

# ---- parameters ----

arguments <- commandArgs(trailingOnly = TRUE)
input_source <- "counts-qc"
input_path <- NULL
input_source_supplied <- FALSE
dry_run <- FALSE
overwrite <- FALSE

argument_index <- 1L
while (argument_index <= length(arguments)) {
  argument <- arguments[[argument_index]]

  if (identical(argument, "--dry-run")) {
    dry_run <- TRUE
    argument_index <- argument_index + 1L
    next
  }
  if (identical(argument, "--overwrite")) {
    overwrite <- TRUE
    argument_index <- argument_index + 1L
    next
  }
  if (argument %in% c("--input-source", "--input")) {
    if (
      argument_index == length(arguments) ||
        startsWith(arguments[[argument_index + 1L]], "--")
    ) {
      stop("Missing value for ", argument, ".", call. = FALSE)
    }

    value <- arguments[[argument_index + 1L]]
    if (identical(argument, "--input-source")) {
      input_source <- value
      input_source_supplied <- TRUE
    } else {
      input_path <- value
    }
    argument_index <- argument_index + 2L
    next
  }

  stop("Unknown argument: ", argument, ".", call. = FALSE)
}

if (!is.null(input_path) && input_source_supplied) {
  stop("Use either --input or --input-source, not both.", call. = FALSE)
}
if (!input_source %in% c("counts-qc", "legacy")) {
  stop(
    "--input-source must be one of counts-qc or legacy.",
    call. = FALSE
  )
}
if (!is.null(input_path)) {
  input_source <- "explicit"
} else {
  input_path <- if (identical(input_source, "counts-qc")) {
    file.path(INPUT_OBJECT_DIR, "sobj_qc_filtered.rds")
  } else {
    file.path(INPUT_OBJECT_DIR, "pipseq_processed_matrix_with_egfp.rds")
  }
}

run_spec <- list(
  input_source = input_source,
  input_path = input_path,
  overwrite = overwrite,
  normalization = "pflog",
  filter_cell_cycle_hvgs = FALSE,
  cluster_elbow_n = 20L,
  sensitivity_dims = c(30L, 50L),
  candidate_resolutions = c(0.3, 0.5, 0.8),
  source_chosen_dims = 30L,
  source_resolution = 0.3,
  mg_chosen_dims = 20L,
  mg_resolution = 0.5,
  mg_pca_dims = 50L,
  expression_layer = "pflog",
  marker_layer = "data",
  module_score_layer = "data",
  counts_layer = "counts"
)

# ---- pipeline plan ----

resolution_tag <- function(value) {
  format(value, trim = TRUE, scientific = FALSE)
}

cell_cycle_tag <- function(filtered) {
  if (isTRUE(filtered)) "filter_cc" else "no_filter_cc"
}

preprocess_path <- function(normalization, filtered) {
  file.path(
    CURRENT_OBJECT_DIR,
    sprintf(
      "preprocess_%s_%s.rds",
      normalization,
      if (isTRUE(filtered)) "filter-cc" else "no-filter-cc"
    )
  )
}

branch_tag <- function(normalization, filtered, dataset_tag = NULL) {
  paste(
    c(normalization, dataset_tag, cell_cycle_tag(filtered)),
    collapse = "_"
  )
}

cluster_path <- function(branch, elbow_n) {
  file.path(
    CURRENT_OBJECT_DIR,
    sprintf("cluster_%s_elbow%d.rds", branch, elbow_n)
  )
}

cluster_column <- function(branch, dims, resolution) {
  sprintf(
    "cluster_%s_dims%d_res%s",
    branch,
    dims,
    resolution_tag(resolution)
  )
}

heatmap_paths <- function(branch, type, output_dir, dims, resolution) {
  output_tag <- switch(
    type,
    marker = sprintf(
      "cell_type_marker_heatmap_%s_%s_cells_dims%d_res%s",
      run_spec$expression_layer,
      branch,
      dims,
      resolution_tag(resolution)
    ),
    module = sprintf(
      "cell_type_module_p27_heatmap_%s_%s_dims%d_res%s",
      run_spec$expression_layer,
      branch,
      dims,
      resolution_tag(resolution)
    )
  )
  file.path(output_dir, paste0(output_tag, c(".png", ".pdf")))
}

mg_figure_paths <- function(branch, dims, resolution) {
  output_tag <- sprintf(
    "mg_selected_cluster_umap_%s_dims%d_res%s",
    branch,
    dims,
    resolution_tag(resolution)
  )
  file.path(FIGURE_DIR, "mg_selected", paste0(output_tag, c(".png", ".pdf")))
}

shell_quote <- function(argument) {
  paste0(
    "'",
    gsub("'", "'\"'\"'", as.character(argument), fixed = TRUE),
    "'"
  )
}

render_command <- function(command) {
  paste(vapply(command, shell_quote, character(1)), collapse = " ")
}

new_stage <- function(
  name,
  command,
  expects,
  protected_outputs = character(),
  validator = NULL
) {
  list(
    name = name,
    command = command,
    expects = expects,
    protected_outputs = protected_outputs,
    validator = validator
  )
}

read_stage_rds <- function(path) {
  tryCatch(
    readRDS(path),
    error = function(error) {
      stop(
        "Cannot read expected RDS output ",
        path,
        ": ",
        conditionMessage(error),
        call. = FALSE
      )
    }
  )
}

validate_seurat_object <- function(object, path) {
  if (!inherits(object, "Seurat")) {
    stop("Expected a Seurat object at ", path, ".", call. = FALSE)
  }
}

validate_counts_output <- function(stage) {
  raw_object <- read_stage_rds(stage$expects[["raw_counts"]])
  validate_seurat_object(raw_object, stage$expects[["raw_counts"]])

  missing_metadata <- setdiff(c("Mouse", "Condition"), colnames(raw_object[[]]))
  if (length(missing_metadata) > 0L) {
    stop(
      "Count output is missing required metadata column(s): ",
      paste(missing_metadata, collapse = ", "),
      ".",
      call. = FALSE
    )
  }
}
validate_preprocess_outputs <- function(stage) {
  expected_branches <- names(stage$expects)
  if (
    is.null(expected_branches) ||
      any(!nzchar(expected_branches))
  ) {
    stop(
      "Preprocess output expectations must be named by branch.",
      call. = FALSE
    )
  }

  for (branch in expected_branches) {
    path <- stage$expects[[branch]]
    sobj <- read_stage_rds(path)
    validate_seurat_object(sobj, path)

    missing_metadata <- setdiff(c("Mouse", "Condition"), colnames(sobj[[]]))
    if (length(missing_metadata) > 0L) {
      stop(
        "Preprocess output ",
        path,
        " is missing required metadata column(s): ",
        paste(missing_metadata, collapse = ", "),
        ".",
        call. = FALSE
      )
    }

    pca_embeddings <- tryCatch(
      SeuratObject::Embeddings(sobj, reduction = "pca"),
      error = function(error) NULL
    )
    if (is.null(pca_embeddings) || ncol(pca_embeddings) != 50L) {
      stop(
        "Preprocess output ",
        path,
        " must contain a 50-PC PCA reduction.",
        call. = FALSE
      )
    }

    branch_parts <- strsplit(branch, "_", fixed = TRUE)[[1L]]
    expected_normalization <- branch_parts[[1L]]
    expected_filtered <- identical(branch_parts[[2L]], "filter")
    preprocessing <- sobj@misc$preprocessing
    if (
      !identical(preprocessing$normalization, expected_normalization) ||
        !identical(
          isTRUE(preprocessing$filtered_cell_cycle),
          expected_filtered
        )
    ) {
      stop(
        "Preprocess output ",
        path,
        " has branch metadata inconsistent with expected branch ",
        branch,
        ".",
        call. = FALSE
      )
    }
  }
}

validate_cluster_output <- function(
  stage,
  expected_branch,
  chosen_column = NULL
) {
  path <- stage$expects[[1L]]
  sobj <- read_stage_rds(path)
  validate_seurat_object(sobj, path)

  preprocessing <- sobj@misc$preprocessing
  branch_parts <- strsplit(expected_branch, "_", fixed = TRUE)[[1L]]
  expected_normalization <- branch_parts[[1L]]
  expected_filtered <- identical(branch_parts[[2L]], "filter")
  if (
    !identical(preprocessing$normalization, expected_normalization) ||
      !identical(
        isTRUE(preprocessing$filtered_cell_cycle),
        expected_filtered
      )
  ) {
    stop(
      "Clustered output ",
      path,
      " has preprocessing metadata inconsistent with branch ",
      expected_branch,
      ".",
      call. = FALSE
    )
  }

  clustering <- sobj@misc$clustering
  if (!identical(clustering$branch_tag, expected_branch)) {
    stop(
      "Clustered output ",
      path,
      " has branch tag ",
      paste(clustering$branch_tag, collapse = ", "),
      "; expected ",
      expected_branch,
      ".",
      call. = FALSE
    )
  }

  candidate_dims <- c(run_spec$cluster_elbow_n, run_spec$sensitivity_dims)
  candidate_columns <- as.vector(outer(
    candidate_dims,
    run_spec$candidate_resolutions,
    FUN = function(dims, resolution) {
      sprintf(
        "cluster_%s_dims%d_res%s",
        expected_branch,
        dims,
        resolution_tag(resolution)
      )
    }
  ))
  missing_candidates <- setdiff(candidate_columns, colnames(sobj[[]]))
  if (length(missing_candidates) > 0L) {
    stop(
      "Clustered output ",
      path,
      " is missing candidate cluster column(s): ",
      paste(missing_candidates, collapse = ", "),
      ".",
      call. = FALSE
    )
  }

  umap_reductions <- sprintf(
    "umap_%s_dims%d",
    expected_branch,
    candidate_dims
  )
  missing_umaps <- setdiff(umap_reductions, names(sobj@reductions))
  if (length(missing_umaps) > 0L) {
    stop(
      "Clustered output ",
      path,
      " is missing candidate UMAP reduction(s): ",
      paste(missing_umaps, collapse = ", "),
      ".",
      call. = FALSE
    )
  }

  if (!is.null(chosen_column) && !chosen_column %in% colnames(sobj[[]])) {
    stop(
      "Chosen source output ",
      path,
      " is missing cluster column ",
      chosen_column,
      ".",
      call. = FALSE
    )
  }
}

make_cluster_validator <- function(expected_branch, chosen_column = NULL) {
  force(expected_branch)
  force(chosen_column)
  function(stage) {
    validate_cluster_output(stage, expected_branch, chosen_column)
  }
}


validate_mg_preprocess_outputs <- function(stage) {
  expected_branches <- names(mg_preprocess_paths)
  if (
    is.null(expected_branches) ||
      !identical(
        sort(expected_branches),
        sort(c("no_filter_cc", "filter_cc"))
      )
  ) {
    stop(
      "MG preprocess output expectations must contain both cell-cycle branches.",
      call. = FALSE
    )
  }

  expected_source_provenance <- list(
    source_cluster_column = run_spec$source_cluster_column,
    source_input = chosen_source_path,
    source_cluster_selection_table = mg_selection_table_path,
    source_cluster_selection_figure = mg_selection_diagnostic_paths[[1L]]
  )

  for (filter_key in expected_branches) {
    path <- mg_preprocess_paths[[filter_key]]
    sobj <- read_stage_rds(path)
    validate_seurat_object(sobj, path)

    missing_metadata <- setdiff(c("Mouse", "Condition"), colnames(sobj[[]]))
    if (length(missing_metadata) > 0L) {
      stop(
        "MG preprocess output ",
        path,
        " is missing required metadata column(s): ",
        paste(missing_metadata, collapse = ", "),
        ".",
        call. = FALSE
      )
    }

    pca_embeddings <- tryCatch(
      SeuratObject::Embeddings(sobj, reduction = "pca"),
      error = function(error) NULL
    )
    if (
      is.null(pca_embeddings) ||
        ncol(pca_embeddings) != run_spec$mg_pca_dims
    ) {
      stop(
        "MG preprocess output ",
        path,
        " must contain a ",
        run_spec$mg_pca_dims,
        "-PC PCA reduction.",
        call. = FALSE
      )
    }

    expected_filtered <- identical(filter_key, "filter_cc")
    preprocessing <- sobj@misc$preprocessing
    if (
      !identical(
        preprocessing$normalization,
        run_spec$normalization
      ) ||
        !identical(
          isTRUE(preprocessing$filtered_cell_cycle),
          expected_filtered
        ) ||
        !identical(
          preprocessing$dataset_tag,
          "mg_selected"
        )
    ) {
      stop(
        "MG preprocess output ",
        path,
        " has normalization, cell-cycle, or dataset metadata ",
        "inconsistent with branch ",
        filter_key,
        ".",
        call. = FALSE
      )
    }

    for (field in names(expected_source_provenance)) {
      if (
        !identical(
          preprocessing[[field]],
          expected_source_provenance[[field]]
        )
      ) {
        stop(
          "MG preprocess output ",
          path,
          " has source provenance field ",
          field,
          " inconsistent with the run specification.",
          call. = FALSE
        )
      }
    }
  }
}

validate_mg_cluster_output <- function(stage, expected_branch) {
  path <- stage$expects[[1L]]
  sobj <- read_stage_rds(path)
  validate_seurat_object(sobj, path)

  missing_metadata <- setdiff(c("Mouse", "Condition"), colnames(sobj[[]]))
  if (length(missing_metadata) > 0L) {
    stop(
      "MG clustered output ",
      path,
      " is missing required metadata column(s): ",
      paste(missing_metadata, collapse = ", "),
      ".",
      call. = FALSE
    )
  }

  preprocessing <- sobj@misc$preprocessing
  expected_filtered <- identical(
    expected_branch,
    branch_tag(
      run_spec$normalization,
      TRUE,
      dataset_tag = "mg_selected"
    )
  )
  if (
    !identical(preprocessing$normalization, run_spec$normalization) ||
      !identical(
        isTRUE(preprocessing$filtered_cell_cycle),
        expected_filtered
      ) ||
      !identical(preprocessing$dataset_tag, "mg_selected")
  ) {
    stop(
      "MG clustered output ",
      path,
      " has preprocessing metadata inconsistent with branch ",
      expected_branch,
      ".",
      call. = FALSE
    )
  }

  expected_source_provenance <- list(
    source_cluster_column = run_spec$source_cluster_column,
    source_input = chosen_source_path,
    source_cluster_selection_table = mg_selection_table_path,
    source_cluster_selection_figure = mg_selection_diagnostic_paths[[1L]]
  )
  for (field in names(expected_source_provenance)) {
    if (
      !identical(
        preprocessing[[field]],
        expected_source_provenance[[field]]
      )
    ) {
      stop(
        "MG clustered output ",
        path,
        " has source provenance field ",
        field,
        " inconsistent with the run specification.",
        call. = FALSE
      )
    }
  }

  clustering <- sobj@misc$clustering
  if (!identical(clustering$branch_tag, expected_branch)) {
    stop(
      "MG clustered output ",
      path,
      " has branch tag ",
      paste(clustering$branch_tag, collapse = ", "),
      "; expected ",
      expected_branch,
      ".",
      call. = FALSE
    )
  }

  candidate_dims <- c(run_spec$cluster_elbow_n, run_spec$sensitivity_dims)
  candidate_columns <- as.vector(outer(
    candidate_dims,
    run_spec$candidate_resolutions,
    FUN = function(dims, resolution) {
      sprintf(
        "cluster_%s_dims%d_res%s",
        expected_branch,
        dims,
        resolution_tag(resolution)
      )
    }
  ))
  missing_candidates <- setdiff(candidate_columns, colnames(sobj[[]]))
  if (length(missing_candidates) > 0L) {
    stop(
      "MG clustered output ",
      path,
      " is missing candidate cluster column(s): ",
      paste(missing_candidates, collapse = ", "),
      ".",
      call. = FALSE
    )
  }
  declared_candidates <- clustering$candidate_names
  if (
    !is.character(declared_candidates) ||
      length(setdiff(candidate_columns, declared_candidates)) > 0L
  ) {
    stop(
      "MG clustered output ",
      path,
      " does not declare all candidate cluster columns.",
      call. = FALSE
    )
  }

  umap_reductions <- sprintf(
    "umap_%s_dims%d",
    expected_branch,
    candidate_dims
  )
  missing_umaps <- setdiff(umap_reductions, names(sobj@reductions))
  if (length(missing_umaps) > 0L) {
    stop(
      "MG clustered output ",
      path,
      " is missing candidate UMAP reduction(s): ",
      paste(missing_umaps, collapse = ", "),
      ".",
      call. = FALSE
    )
  }

  if (!run_spec$mg_cluster_column %in% colnames(sobj[[]])) {
    stop(
      "MG clustered output ",
      path,
      " is missing chosen cluster column ",
      run_spec$mg_cluster_column,
      ".",
      call. = FALSE
    )
  }
}

make_mg_cluster_validator <- function(expected_branch) {
  force(expected_branch)
  function(stage) validate_mg_cluster_output(stage, expected_branch)
}

validate_qc_outputs <- function(stage) {
  annotated_path <- stage$expects[["annotated_raw"]]
  filtered_path <- stage$expects[["filtered"]]
  annotated_object <- read_stage_rds(annotated_path)
  filtered_object <- read_stage_rds(filtered_path)
  validate_seurat_object(annotated_object, annotated_path)
  validate_seurat_object(filtered_object, filtered_path)

  annotated_metadata <- annotated_object[[]]
  filtered_metadata <- filtered_object[[]]
  missing_annotation_columns <- setdiff(
    c("is_cell", "pass_qc"),
    colnames(annotated_metadata)
  )
  if (length(missing_annotation_columns) > 0L) {
    stop(
      "Annotated QC output is missing required metadata column(s): ",
      paste(missing_annotation_columns, collapse = ", "),
      ".",
      call. = FALSE
    )
  }
  if (!is.logical(annotated_metadata$pass_qc)) {
    stop("Annotated QC output pass_qc metadata must be logical.", call. = FALSE)
  }

  missing_filtered_columns <- setdiff(
    c("Mouse", "Condition"),
    colnames(filtered_metadata)
  )
  if (length(missing_filtered_columns) > 0L) {
    stop(
      "Filtered QC output is missing required metadata column(s): ",
      paste(missing_filtered_columns, collapse = ", "),
      ".",
      call. = FALSE
    )
  }

  expected_cells <- colnames(annotated_object)[
    annotated_metadata$pass_qc %in% TRUE
  ]
  if (!identical(colnames(filtered_object), expected_cells)) {
    stop(
      "Filtered QC cells do not exactly match annotated cells with pass_qc TRUE.",
      call. = FALSE
    )
  }
}

validate_stage_outputs <- function(stage) {
  missing_paths <- stage$expects[!file.exists(stage$expects)]
  if (length(missing_paths) > 0L) {
    stop(
      "Stage ",
      stage$name,
      " did not create expected output(s): ",
      paste(missing_paths, collapse = "; "),
      call. = FALSE
    )
  }
  if (is.function(stage$validator)) {
    stage$validator(stage)
  }
}

run_stage <- function(stage) {
  message("Running stage ", stage$name, ": ", render_command(stage$command))
  status <- tryCatch(
    suppressWarnings(
      system2(
        command = stage$command[[1]],
        args = stage$command[-1],
        stdout = "",
        stderr = ""
      )
    ),
    error = function(error) {
      stop(
        "Stage ",
        stage$name,
        " could not start: ",
        conditionMessage(error),
        call. = FALSE
      )
    }
  )
  if (!identical(status, 0L)) {
    stop(
      "Stage ",
      stage$name,
      " failed with exit status ",
      status,
      ".",
      call. = FALSE
    )
  }
  tryCatch(
    validate_stage_outputs(stage),
    error = function(error) {
      stop(
        "Stage ",
        stage$name,
        " output validation failed: ",
        conditionMessage(error),
        call. = FALSE
      )
    }
  )
  message("Completed stage ", stage$name, ".")
}

